import React, { useState, useEffect } from 'react';
import './CommandeList.css';

const CommandeList = ({ onSelect }) => {
  const [commandes, setCommandes] = useState([]);

  const fetchCommandes = async () => {
    try {
      const res = await fetch('http://localhost:3001/commandes');
      const data = await res.json();
      setCommandes(data);
    } catch (err) {
      console.error('Erreur lors du chargement des commandes :', err);
    }
  };

  useEffect(() => {
    fetchCommandes();
  }, []);

  const handleDelete = async (codeCom) => {
    if (!window.confirm('Supprimer cette commande ?')) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${codeCom}`, {
        method: 'DELETE'
      });
      if (!res.ok) throw new Error(`Erreur ${res.status}`);
      fetchCommandes();
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <div className="commande-list">
      <h3>Liste des Commandes</h3>
      <table>
        <thead>
          <tr>
            <th>Code</th>
            <th>Client</th>
            <th>Article</th>
            <th>Date</th>
            <th>Quantité</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {commandes.map((com) => (
            <tr key={com.codeCom}>
              <td>{com.codeCom}</td>
              <td>{com.nomCli} {com.prenomCli}</td>
              <td>{com.nomArt}</td>
              <td>{com.dateCom?.split('T')[0]}</td>
              <td>{com.QteCom}</td>
              <td>
              <button onClick={() => onSelect(com)}>
                  Modifier / Supprimer
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default CommandeList;
